// src/App.js
import React from 'react';
import { ThemeProvider, createTheme } from '@mui/material/styles';
import CssBaseline from '@mui/material/CssBaseline';
import LeetcodeLeaderboard from '/components/LeetcodeLeaderboard';
import CodeforcesLeaderboard from '/components/CodeforcesLeaderboard';

const darkTheme = createTheme({
  palette: {
    mode: 'dark',
    // You can customize additional palette values here if desired.
  },
});

function App() {
  return (
    <ThemeProvider theme={darkTheme}>
      {/* CssBaseline applies global dark mode styles */}
      <CssBaseline />
      <div>
        <LeetcodeLeaderboard />
        <CodeforcesLeaderboard />
      </div>
    </ThemeProvider>
  );
}

export default App;
